INSERT INTO questions (subject, topic, difficulty, question_text, choices, correct_answer, explanation, exam_type) VALUES
('Professional Education','Facilitating Learning','medium','Which learning theory emphasizes the whole is greater than the sum of its parts?','[{"key":"A","text":"Behaviorism"},{"key":"B","text":"Cognitivism"},{"key":"C","text":"Gestalt psychology"},{"key":"D","text":"Humanism"}]','C','Gestalt psychology focuses on how the mind organizes sensory information into meaningful wholes and patterns.','both'),
('Professional Education','Facilitating Learning','easy','Modeling as a teaching strategy is based on:','[{"key":"A","text":"Pavlov''s classical conditioning"},{"key":"B","text":"Bandura''s observational learning"},{"key":"C","text":"Skinner''s operant conditioning"},{"key":"D","text":"Piaget''s constructivism"}]','B','Modeling involves demonstrating a behavior for students to observe and imitate, rooted in Bandura''s social learning theory.','both'),
('Professional Education','Facilitating Learning','medium','A student who studies because they genuinely enjoy the subject demonstrates:','[{"key":"A","text":"Extrinsic motivation"},{"key":"B","text":"Instrumental motivation"},{"key":"C","text":"Intrinsic motivation"},{"key":"D","text":"Achievement motivation"}]','C','Intrinsic motivation arises from internal factors like genuine interest and enjoyment of the activity itself.','both'),
('Professional Education','Facilitating Learning','medium','Chunking in information processing refers to:','[{"key":"A","text":"Breaking a lesson into daily parts"},{"key":"B","text":"Grouping individual pieces of information into meaningful units"},{"key":"C","text":"Separating students by ability"},{"key":"D","text":"Using flash cards for memorization"}]','B','Chunking increases working memory capacity by grouping information into larger, meaningful units (e.g., remembering a phone number).','both'),
('Professional Education','Facilitating Learning','hard','The "spacing effect" in learning research shows that:','[{"key":"A","text":"Massed practice is more effective than distributed practice"},{"key":"B","text":"Distributed practice over time leads to better long-term retention"},{"key":"C","text":"Short intensive study sessions are always best"},{"key":"D","text":"Frequency of review has no effect on retention"}]','B','The spacing effect demonstrates that studying material over spaced intervals produces superior long-term memory compared to cramming.','both'),
('Professional Education','Facilitating Learning','medium','Think-Pair-Share is a strategy that promotes:','[{"key":"A","text":"Individual silent work"},{"key":"B","text":"Active processing, peer discussion, and class sharing"},{"key":"C","text":"Teacher-centered lecturing"},{"key":"D","text":"Written examinations"}]','B','Think-Pair-Share engages all learners by having them reflect, discuss with a partner, then share with the class.','both'),
('Professional Education','Facilitating Learning','easy','Which theorist is associated with the "hierarchy of needs" applied to motivation in education?','[{"key":"A","text":"B.F. Skinner"},{"key":"B","text":"Abraham Maslow"},{"key":"C","text":"Carl Rogers"},{"key":"D","text":"Albert Bandura"}]','B','Maslow''s hierarchy of needs (physiological → safety → love → esteem → self-actualization) is widely applied to classroom motivation.','both'),
('Professional Education','Assessment of Learning','easy','Formative assessment is primarily used to:','[{"key":"A","text":"Assign final grades"},{"key":"B","text":"Monitor student learning and provide feedback during instruction"},{"key":"C","text":"Rank students at the end of a term"},{"key":"D","text":"Select students for advanced programs"}]','B','Formative assessment is ongoing assessment during learning to guide instruction and provide feedback.','both'),
('Professional Education','Assessment of Learning','easy','Summative assessment is used to:','[{"key":"A","text":"Diagnose learning difficulties before instruction"},{"key":"B","text":"Provide feedback during the learning process"},{"key":"C","text":"Evaluate student achievement at the end of a unit or course"},{"key":"D","text":"Group students for instruction"}]','C','Summative assessment evaluates what students have learned at the end of an instructional period (e.g., final exams, unit tests).','both'),
('Professional Education','Assessment of Learning','medium','Validity in assessment means:','[{"key":"A","text":"The assessment produces consistent results"},{"key":"B","text":"The assessment measures what it is supposed to measure"},{"key":"C","text":"The assessment is easy to administer"},{"key":"D","text":"All students score similarly"}]','B','Validity is the degree to which an assessment accurately measures the intended knowledge, skills, or abilities.','both'),
('Professional Education','Assessment of Learning','medium','Reliability in assessment refers to:','[{"key":"A","text":"The assessment measures the right content"},{"key":"B","text":"The consistency of assessment results across repeated administration"},{"key":"C","text":"The fairness of the scoring procedure"},{"key":"D","text":"The difficulty level of test items"}]','B','Reliability means the assessment produces stable, consistent results when administered under similar conditions.','both'),
('Professional Education','Assessment of Learning','hard','A test that is reliable but not valid is:','[{"key":"A","text":"Acceptable for high-stakes decisions"},{"key":"B","text":"Consistently measuring the wrong thing"},{"key":"C","text":"Both accurate and consistent"},{"key":"D","text":"Always suitable for classroom use"}]','B','A reliable test consistently produces the same results, but if those results don''t reflect the intended construct, it is not valid.','both'),
('Professional Education','Assessment of Learning','medium','The item difficulty index (p) of 0.90 indicates:','[{"key":"A","text":"The item is very difficult"},{"key":"B","text":"The item is very easy"},{"key":"C","text":"The item has good discrimination"},{"key":"D","text":"The item is invalid"}]','B','An item difficulty index close to 1.0 means most students answered correctly — the item is easy.','both'),
('Professional Education','Assessment of Learning','medium','Item discrimination index tells us:','[{"key":"A","text":"How difficult an item is"},{"key":"B","text":"How well an item distinguishes high from low performers"},{"key":"C","text":"The number of students who answered correctly"},{"key":"D","text":"The time needed to answer an item"}]','B','The discrimination index measures how effectively an item separates students who know the material from those who do not.','both'),
('Professional Education','Assessment of Learning','easy','A portfolio assessment collects:','[{"key":"A","text":"Only final exam results"},{"key":"B","text":"Evidence of student learning over time"},{"key":"C","text":"Standardized test scores only"},{"key":"D","text":"Teacher observations only"}]','B','Portfolios systematically collect student work samples over time to demonstrate growth and achievement.','both'),
('Professional Education','Assessment of Learning','medium','Authentic assessment requires students to:','[{"key":"A","text":"Answer multiple choice questions"},{"key":"B","text":"Demonstrate knowledge through real-world tasks"},{"key":"C","text":"Memorize and recite content"},{"key":"D","text":"Take standardized tests"}]','B','Authentic assessment involves tasks that reflect real-world application of knowledge and skills.','both'),
('Professional Education','Assessment of Learning','medium','A rubric provides:','[{"key":"A","text":"A list of student names"},{"key":"B","text":"Clear criteria and performance levels for evaluating student work"},{"key":"C","text":"Raw scores for standardized tests"},{"key":"D","text":"Attendance records"}]','B','Rubrics describe the criteria and levels of quality used to evaluate student performance consistently.','both'),
('Professional Education','Assessment of Learning','medium','Norm-referenced assessment compares:','[{"key":"A","text":"Student performance against a fixed standard"},{"key":"B","text":"Student performance against others in the norm group"},{"key":"C","text":"Student performance against their own past results"},{"key":"D","text":"Different schools'' curricula"}]','B','Norm-referenced tests rank students relative to a norming group (e.g., national average); used for percentile ranks.','both'),
('Professional Education','Assessment of Learning','medium','Criterion-referenced assessment compares student performance to:','[{"key":"A","text":"Other students in the class"},{"key":"B","text":"National norms"},{"key":"C","text":"A predetermined standard or learning objective"},{"key":"D","text":"Teacher expectations"}]','C','Criterion-referenced tests measure whether students have achieved specific learning outcomes, not how they compare to others.','both'),
('Professional Education','Assessment of Learning','easy','Diagnostic assessment is conducted:','[{"key":"A","text":"At the end of a unit"},{"key":"B","text":"Before instruction to identify student strengths and weaknesses"},{"key":"C","text":"During instruction as feedback"},{"key":"D","text":"To assign final grades"}]','B','Diagnostic assessment is given before instruction to understand what students already know and identify gaps.','both'),
('Professional Education','Assessment of Learning','hard','The Table of Specifications (TOS) in test construction ensures:','[{"key":"A","text":"All questions are of equal difficulty"},{"key":"B","text":"Test items are aligned to objectives and proportionally distributed across topics"},{"key":"C","text":"Tests are easy enough for all students"},{"key":"D","text":"Questions are arranged randomly"}]','B','The TOS maps test items to instructional objectives by topic and cognitive level to ensure content validity.','both'),
('Professional Education','Assessment of Learning','medium','Which measure of central tendency is most affected by extreme scores?','[{"key":"A","text":"Mode"},{"key":"B","text":"Median"},{"key":"C","text":"Mean"},{"key":"D","text":"Range"}]','C','The mean (average) is sensitive to extreme values (outliers), unlike the median or mode.','both'),
('Professional Education','Assessment of Learning','medium','A student scores at the 75th percentile. This means:','[{"key":"A","text":"They answered 75% of items correctly"},{"key":"B","text":"They scored higher than 75% of the norm group"},{"key":"C","text":"They failed the exam"},{"key":"D","text":"They scored 75 points out of 100"}]','B','A percentile rank of 75 means the student scored equal to or higher than 75% of the comparison group.','both'),
('Professional Education','Assessment of Learning','hard','An analytic rubric differs from a holistic rubric in that it:','[{"key":"A","text":"Gives one overall score for the entire performance"},{"key":"B","text":"Evaluates each criterion separately with its own score"},{"key":"C","text":"Only works for objective tests"},{"key":"D","text":"Does not use performance levels"}]','B','Analytic rubrics score each dimension/criterion independently, providing detailed feedback; holistic rubrics give a single overall score.','both'),
('Professional Education','Assessment of Learning','medium','Self-assessment in the classroom develops:','[{"key":"A","text":"Dependence on the teacher for evaluation"},{"key":"B","text":"Metacognitive awareness and learner responsibility"},{"key":"C","text":"Competition among students"},{"key":"D","text":"Standardized performance"}]','B','Self-assessment develops students'' ability to reflect on and judge their own work, fostering metacognition and autonomy.','both'),
('Professional Education','Assessment of Learning','medium','Performance-based assessment is most suitable for measuring:','[{"key":"A","text":"Factual recall of information"},{"key":"B","text":"Applied skills and complex thinking"},{"key":"C","text":"Speed of reading"},{"key":"D","text":"Attendance records"}]','B','Performance-based assessment evaluates how well students apply knowledge and skills in real or simulated tasks.','both'),
('Professional Education','Assessment of Learning','easy','In a normal distribution, what percentage of scores falls within one standard deviation of the mean?','[{"key":"A","text":"50%"},{"key":"B","text":"68%"},{"key":"C","text":"95%"},{"key":"D","text":"99%"}]','B','In a normal distribution, approximately 68% of data falls within ±1 standard deviation of the mean.','both'),
('Professional Education','Assessment of Learning','medium','Higher-order thinking skills (HOTS) in assessment require students to:','[{"key":"A","text":"Recall and memorize facts"},{"key":"B","text":"Analyze, evaluate, and create"},{"key":"C","text":"Copy examples from the board"},{"key":"D","text":"Complete drill and practice"}]','B','HOTS involves Bloom''s upper levels — analysis, evaluation, and creation — requiring deeper cognitive processing.','both'),
('Professional Education','Assessment of Learning','medium','The standard deviation in a test measures:','[{"key":"A","text":"The highest score achieved"},{"key":"B","text":"The spread or variability of scores around the mean"},{"key":"C","text":"The average score of the class"},{"key":"D","text":"The number of students who passed"}]','B','Standard deviation indicates how much scores vary from the mean; a high SD means scores are widely spread.','both'),
('Professional Education','Assessment of Learning','hard','When a test consistently measures something other than what it was designed to measure, it has:','[{"key":"A","text":"High reliability but low validity"},{"key":"B","text":"High validity but low reliability"},{"key":"C","text":"Both high validity and reliability"},{"key":"D","text":"Neither validity nor reliability"}]','A','A test can be reliable (consistent) yet invalid (measuring the wrong construct) — reliability does not guarantee validity.','both'),
('Professional Education','Assessment of Learning','medium','The best type of assessment for measuring practical laboratory skills is:','[{"key":"A","text":"Multiple choice test"},{"key":"B","text":"True-false test"},{"key":"C","text":"Performance-based assessment"},{"key":"D","text":"Essay test"}]','C','Laboratory skills are best assessed through direct observation of performance — a hallmark of performance-based assessment.','both'),
('Professional Education','Assessment of Learning','medium','Peer assessment in the classroom:','[{"key":"A","text":"Replaces the teacher''s grading responsibility"},{"key":"B","text":"Develops evaluative skills and promotes collaborative learning"},{"key":"C","text":"Is unreliable and should be avoided"},{"key":"D","text":"Only works for older students"}]','B','Peer assessment enhances critical thinking, develops evaluation skills, and encourages students to learn from each other.','both'),
('Professional Education','Curriculum Development','medium','Tyler''s Rationale (1949) begins curriculum development with:','[{"key":"A","text":"Selecting learning experiences"},{"key":"B","text":"Determining educational purposes"},{"key":"C","text":"Organizing learning experiences"},{"key":"D","text":"Evaluating outcomes"}]','B','Tyler''s four-step model starts with identifying educational purposes/objectives, then selecting experiences, organizing, and evaluating.','both'),
('Professional Education','Curriculum Development','medium','The hidden curriculum refers to:','[{"key":"A","text":"Secret government education plans"},{"key":"B","text":"Unwritten, informal lessons students learn in school"},{"key":"C","text":"Advanced curriculum for gifted students"},{"key":"D","text":"Online curriculum resources"}]','B','The hidden curriculum encompasses implicit messages, values, and norms students learn through the school culture and environment.','both'),
('Professional Education','Curriculum Development','medium','The null curriculum refers to:','[{"key":"A","text":"Topics teachers choose to skip"},{"key":"B","text":"What is NOT taught but students notice is absent"},{"key":"C","text":"The official government curriculum"},{"key":"D","text":"After-school programs"}]','B','Eisner''s null curriculum refers to what schools choose not to teach — the absence itself sends a message about value.','both'),
('Professional Education','Curriculum Development','easy','The K-12 curriculum in the Philippines was implemented under:','[{"key":"A","text":"Republic Act 7836"},{"key":"B","text":"Republic Act 10533"},{"key":"C","text":"Republic Act 9293"},{"key":"D","text":"Republic Act 7722"}]','B','RA 10533 (Enhanced Basic Education Act of 2013) mandated the K-12 curriculum adding Grades 11 and 12.','both'),
('Professional Education','Curriculum Development','medium','Spiral progression in the K-12 curriculum means:','[{"key":"A","text":"Students skip grades based on performance"},{"key":"B","text":"Topics are revisited at increasing levels of complexity across grades"},{"key":"C","text":"Curriculum only covers Math and Science"},{"key":"D","text":"Teachers rotate subjects yearly"}]','B','Spiral progression revisits key concepts at progressively deeper levels as learners advance, building on prior knowledge.','both');
